    let mut keyframe_paths: Vec<PathBuf> = std::fs::read_dir(&args.keyframes)
        .with_context(|| format!("Cannot read keyframes dir: {:?}", args.keyframes))?
        .filter_map(|e| e.ok())
        .map(|e| e.path())
        .filter(|p| p.extension().map(|e| e.eq_ignore_ascii_case("png")).unwrap_or(false))
        .collect();
    keyframe_paths.sort();

